. parse_frequency(frequency):
    """
    Given a frequency string with a number and a unit of time, return a corresponding
    datetime.timedelta instance or None if the frequency is None or "always".

    For instance, given "3 weeks", return datetime.timedelta(weeks=3)

    Raise ValueError if the given frequency cannot be parsed.
    """
    import re
    import datetime

    if frequency is None or frequency == "always":
        return None

    match = re.match(r"(\d+)(?:days|weeks|months|years)", frequency)
    if not match:
        raise ValueError("Invalid frequency format")

    number = int(match.group(1))
    unit = match.group(2)

    if unit == "days":
        return datetime.timedelta(days=number)
    elif unit == "weeks":
        return datetime.timedelta(weeks=number)
    elif unit == "months":
        return datetime.timedelta(months=number)
    elif unit == "years":
        return datetime.timedelta(years=number)
    else:
        raise ValueError(f"Invalid unit: {unit}")<|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|><|endoftext|>

