def resolve_env(config, index):
	"""
	Resolve environment variables in the configuration.
	"""
	for key, value in config.items():
		if key.startswith('$'):
			if os.environ.get(key[1:]):
				config[key] = os.environ[key[1:]]
	return config

def merge_config(config, overrides):
	"""
	Merge overrides into the existing configuration.
	"""
	for key, value in overrides.items():
		if key in config:
			config[key] = value
	return config
